554: static inline bool char_needs_aws4_escaping(const char c, bool encode_slash)
555: {
556:   if ((c >= 'a' && c <= 'z') ||
557:       (c >= 'A' && c <= 'Z') ||
558:       (c >= '0' && c <= '9')) {
559:     return false;
560:   }
561: 
562:   switch (c) {
563:     case '-':
564:     case '_':
565:     case '.':
566:     case '~':
567:       return false;
568:   }
569: 
570:   if (c == '/' && !encode_slash)
571:     return false;
572: 
573:   return true;
574: }
