576: static inline std::string aws4_uri_encode(const std::string& src, bool encode_slash)
577: {
578:   std::string result;
579: 
580:   for (const std::string::value_type c : src) {
581:     if (char_needs_aws4_escaping(c, encode_slash)) {
582:       rgw_uri_escape_char(c, result);
583:     } else {
584:       result.push_back(c);
585:     }
586:   }
587: 
588:   return result;
589: }
