629: static inline const string calc_v4_payload_hash(const string& payload)
630: {
631:   ceph::crypto::SHA256* sha256_hash = calc_hash_sha256_open_stream();
632:   calc_hash_sha256_update_stream(sha256_hash, payload.c_str(), payload.length());
633:   const auto payload_hash = calc_hash_sha256_close_stream(&sha256_hash);
634:   return payload_hash;
635: }
