637: static inline const char* get_v4_exp_payload_hash(const req_info& info)
638: {
639:   /* In AWSv4 the hash of real, transferred payload IS NOT necessary to form
640:    * a Canonical Request, and thus verify a Signature. x-amz-content-sha256
641:    * header lets get the information very early -- before seeing first byte
642:    * of HTTP body. As a consequence, we can decouple Signature verification
643:    * from payload's fingerprint check. */
644:   const char *expected_request_payload_hash = \
645:     info.env->get("HTTP_X_AMZ_CONTENT_SHA256");
646: 
647:   if (!expected_request_payload_hash) {
648:     /* An HTTP client MUST send x-amz-content-sha256. The single exception
649:      * is the case of using the Query Parameters where "UNSIGNED-PAYLOAD"
650:      * literals are used for crafting Canonical Request:
651:      *
652:      *  You don't include a payload hash in the Canonical Request, because
653:      *  when you create a presigned URL, you don't know the payload content
654:      *  because the URL is used to upload an arbitrary payload. Instead, you
655:      *  use a constant string UNSIGNED-PAYLOAD. */
656:     expected_request_payload_hash = AWS4_UNSIGNED_PAYLOAD_HASH;
657:   }
658: 
659:   return expected_request_payload_hash;
660: }
