705: std::string get_v4_canonical_method(const req_state* s)
706: {
707:   /* If this is a OPTIONS request we need to compute the v4 signature for the
708:    * intended HTTP method and not the OPTIONS request itself. */
709:   if (s->op_type == RGW_OP_OPTIONS_CORS) {
710:     const char *cors_method = s->info.env->get("HTTP_ACCESS_CONTROL_REQUEST_METHOD");
711: 
712:     if (cors_method) {
713:       /* Validate request method passed in access-control-request-method is valid. */
714:       auto cors_flags = get_cors_method_flags(cors_method);
715:       if (!cors_flags) {
716:           ldpp_dout(s, 1) << "invalid access-control-request-method header = "
717:                           << cors_method << dendl;
718:           throw -EINVAL;
719:       }
720: 
721:       ldpp_dout(s, 10) << "canonical req method = " << cors_method
722:                        << ", due to access-control-request-method header" << dendl;
723:       return cors_method;
724:     } else {
725:       ldpp_dout(s, 1) << "invalid http options req missing "
726:                       << "access-control-request-method header" << dendl;
727:       throw -EINVAL;
728:     }
729:   }
730: 
731:   return s->info.method;
732: }
