734: boost::optional<std::string>
735: get_v4_canonical_headers(const req_info& info,
736:                          const std::string_view& signedheaders,
737:                          const bool using_qs,
738:                          const bool force_boto2_compat)
739: {
740:   std::map<std::string_view, std::string> canonical_hdrs_map;
741:   for (const auto& token : get_str_vec<5>(signedheaders, ";")) {
742:     /* TODO(rzarzynski): we'd like to switch to sstring here but it should
743:      * get push_back() and reserve() first. */
744:     std::string token_env = "HTTP_";
745:     token_env.reserve(token.length() + sarrlen("HTTP_") + 1);
746: 
747:     /* XXX can we please stop doing this? */
748:     std::transform(std::begin(token), std::end(token),
749:                    std::back_inserter(token_env), [](const int c) {
750:                      return c == '-' ? '_' : c == '_' ? '-' : std::toupper(c);
751:                    });
752: 
753:     if (token_env == "HTTP_CONTENT_LENGTH") {
754:       token_env = "CONTENT_LENGTH";
755:     } else if (token_env == "HTTP_CONTENT_TYPE") {
756:       token_env = "CONTENT_TYPE";
757:     }
758:     const char* const t = info.env->get(token_env.c_str());
759:     if (!t) {
760:       dout(10) << "warning env var not available " << token_env.c_str() << dendl;
761:       continue;
762:     }
763: 
764:     std::string token_value(t);
765:     if (token_env == "HTTP_CONTENT_MD5" &&
766:         !std::all_of(std::begin(token_value), std::end(token_value),
767:                      is_base64_for_content_md5)) {
768:       dout(0) << "NOTICE: bad content-md5 provided (not base64)"
769:             << ", aborting request" << dendl;
770:       return boost::none;
771:     }
772: 
773:     if (force_boto2_compat && using_qs && token == "host") {
774:       std::string_view port = info.env->get("SERVER_PORT", "");
775:       std::string_view secure_port = info.env->get("SERVER_PORT_SECURE", "");
776: 
777:       if (!secure_port.empty()) {
778: 	if (secure_port != "443")
779: 	  token_value.append(":", sarrlen(":"))
780:                      .append(secure_port.data(), secure_port.length());
781:       } else if (!port.empty()) {
782: 	if (port != "80")
783: 	  token_value.append(":", sarrlen(":"))
784:                      .append(port.data(), port.length());
785:       }
786:     }
787: 
788:     canonical_hdrs_map[token] = rgw_trim_whitespace(token_value);
789:   }
790: 
791:   std::string canonical_hdrs;
792:   for (const auto& header : canonical_hdrs_map) {
793:     const std::string_view& name = header.first;
794:     std::string value = header.second;
795:     boost::trim_all<std::string>(value);
796: 
797:     canonical_hdrs.append(name.data(), name.length())
798:                   .append(":", sarrlen(":"))
799:                   .append(value)
800:                   .append("\n", sarrlen("\n"));
801:   }
802:   return canonical_hdrs;
803: }
