805: static void handle_header(const string& header, const string& val,
806:                           std::map<std::string, std::string> *canonical_hdrs_map)
807: {
808:   /* TODO(rzarzynski): we'd like to switch to sstring here but it should
809:    * get push_back() and reserve() first. */
810: 
811:   std::string token;
812:   token.reserve(header.length());
813: 
814:   if (header == "HTTP_CONTENT_LENGTH") {
815:     token = "content-length";
816:   } else if (header == "HTTP_CONTENT_TYPE") {
