978: static sha256_digest_t
979: get_v4_signing_key(CephContext* const cct,
980:                    const std::string_view& credential_scope,
981:                    const std::string_view& secret_access_key,
982:                    const DoutPrefixProvider *dpp)
983: {
984:   std::string_view date, region, service;
985:   std::tie(date, region, service) = parse_cred_scope(credential_scope);
986: 
987:   const auto utfed_sec_key = transform_secret_key(secret_access_key);
988:   const auto date_k = calc_hmac_sha256(utfed_sec_key, date);
989:   const auto region_k = calc_hmac_sha256(date_k, region);
990:   const auto service_k = calc_hmac_sha256(region_k, service);
991: 
992:   /* aws4_request */
993:   const auto signing_key = calc_hmac_sha256(service_k,
994:                                             std::string_view("aws4_request"));
995: 
996:   ldpp_dout(dpp, 10) << "date_k    = " << date_k << dendl;
997:   ldpp_dout(dpp, 10) << "region_k  = " << region_k << dendl;
998:   ldpp_dout(dpp, 10) << "service_k = " << service_k << dendl;
999:   ldpp_dout(dpp, 10) << "signing_k = " << signing_key << dendl;
1000: 
1001:   return signing_key;
1002: }
