268:   auto cur_tp = ceph::coarse_real_clock::now();
269: 
270:   if (std::chrono::abs(cur_tp - req_tp) > RGW_AUTH_GRACE) {
271:     dout(10) << "NOTICE: request time skew too big." << dendl;
272:     using ceph::operator<<;
273:     dout(10) << "req_tp=" << req_tp << ", cur_tp=" << cur_tp << dendl;
274:     return false;
275:   }
276: 
277:   return true;
278: }
