280: static inline int parse_v4_query_string(const req_info& info,              /* in */
281:                                         std::string_view& credential,    /* out */
282:                                         std::string_view& signedheaders, /* out */
283:                                         std::string_view& signature,     /* out */
284:                                         std::string_view& date,          /* out */
285:                                         std::string_view& sessiontoken)  /* out */
286: {
287:   /* auth ships with req params ... */
288: 
289:   /* look for required params */
290:   credential = info.args.get("x-amz-credential");
291:   if (credential.size() == 0) {
292:     return -EPERM;
293:   }
294: 
295:   date = info.args.get("x-amz-date");
296:   struct tm date_t;
297:   if (!parse_iso8601(sview2cstr(date).data(), &date_t, nullptr, false)) {
298:     return -EPERM;
299:   }
300: 
301:   std::string_view expires = info.args.get("x-amz-expires");
302:   if (expires.empty()) {
303:     return -EPERM;
304:   }
305:   /* X-Amz-Expires provides the time period, in seconds, for which
306:      the generated presigned URL is valid. The minimum value
307:      you can set is 1, and the maximum is 604800 (seven days) */
308:   time_t exp = atoll(expires.data());
309:   if ((exp < 1) || (exp > 7*24*60*60)) {
310:     dout(10) << "ERROR: exp out of range, exp = " << exp << dendl;
311:     return -EPERM;
312:   }
313:   /* handle expiration in epoch time */
314:   uint64_t req_sec = (uint64_t)internal_timegm(&date_t);
315:   uint64_t now = ceph_clock_now();
316:   if (now >= req_sec + exp) {
317:     dout(10) << "ERROR: presigned URL has expired, now = " << now << ", req_sec = " << req_sec << ", exp = " << exp << dendl;
318:     return -ERR_PRESIGNED_URL_EXPIRED;
319:   }
320: 
321:   signedheaders = info.args.get("x-amz-signedheaders");
322:   if (signedheaders.size() == 0) {
323:     return -EPERM;
324:   }
325: 
326:   signature = info.args.get("x-amz-signature");
327:   if (signature.size() == 0) {
328:     return -EPERM;
329:   }
330: 
331:   if (info.args.exists("x-amz-security-token")) {
332:     sessiontoken = info.args.get("x-amz-security-token");
333:     if (sessiontoken.size() == 0) {
334:       return -EPERM;
335:     }
336:   }
337: 
338:   return 0;
339: }
