341: static bool get_next_token(const std::string_view& s,
342:                            size_t& pos,
343:                            const char* const delims,
344:                            std::string_view& token)
345: {
346:   const size_t start = s.find_first_not_of(delims, pos);
347:   if (start == std::string_view::npos) {
348:     pos = s.size();
349:     return false;
350:   }
351: 
352:   size_t end = s.find_first_of(delims, start);
353:   if (end != std::string_view::npos)
354:     pos = end + 1;
355:   else {
356:     pos = end = s.size();
357:   }
358: 
359:   token = s.substr(start, end - start);
360:   return true;
361: }
